static double fast_exp(double x)
{
	x = 1.0 + x * 0.000244140625;
	x *= x; x *= x; x *= x; x *= x;
	x *= x; x *= x; x *= x; x *= x;
	x *= x; x *= x; x *= x; x *= x;
	return x;
}

static int compare_double_asc(const void *a, const void *b)
{
	double da = *(const double *)a;
	double db = *(const double *)b;
	if( da < db ) return -1;
	if( da > db ) return 1;
	return 0;
}

